def transform(grid):
    R,C=len(grid),len(grid[0])
    from collections import Counter
    flat=[grid[r][c] for r in range(R) for c in range(C)]
    bg=Counter(flat).most_common(1)[0][0]
    # Find two bordered windows and extract their contents combined
    visited=[[False]*C for _ in range(R)]
    windows=[]
    for bv in set(flat)-{bg}:
        for sr in range(R):
            for sc in range(C):
                if grid[sr][sc]==bv and not visited[sr][sc]:
                    # Check if row border exists
                    if sum(1 for c in range(C) if grid[sr][c]==bv)>=3:
                        r1=sr
                        while r1+1<R and any(grid[r1+1][c]==bv for c in range(sc,min(sc+10,C))): r1+=1
                        c1=sc
                        while c1+1<C and grid[sr][c1+1]==bv: c1+=1
                        for r in range(sr,r1+1):
                            for c in range(sc,c1+1): visited[r][c]=True
                        if r1>sr+1 and c1>sc+1:
                            interior=[[grid[r][c] for c in range(sc+1,c1)] for r in range(sr+1,r1)]
                            windows.append(interior)
    if not windows:
        return [[grid[r][c] for c in range(C)] for r in range(R)]
    # Find smallest window (that's likely the output)
    windows.sort(key=lambda w: len(w)*len(w[0]) if w and w[0] else 0)
    # Overlay all window contents
    out=windows[0]
    H=len(out); W=len(out[0]) if out else 0
    for w in windows[1:]:
        for r in range(min(len(w),H)):
            for c in range(min(len(w[r]) if w else 0,W)):
                if w[r][c]!=bg and out[r][c]==bg: out[r][c]=w[r][c]
    return out
